/*
 * IoT Network Scalability Simulation
 * 
 * This program simulates network cell capacity management that
 * network operators require for massive IoT deployments.
 * Demonstrates NB-IoT/LTE-M cell tower connection handling.
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>

/* Network capacity constants based on technology types */
#define MAX_CONNECTIONS_3G 500 /* Traditional 3G cell */
#define MAX_CONNECTIONS_4G 2000 /* Standard 4G cell */
#define MAX_CONNECTIONS_NBIOT 100000 /* NB-IoT can handle ~100k devices/cell */
#define MAX_CONNECTIONS_LTEM 50000 /* LTE-M can handle ~50k devices/cell */

/* Power state definitions for IoT devices */
typedef enum {
 PS_ACTIVE, /* Device transmitting/receiving */
 PS_IDLE, /* Connected, waiting for data */
 PS_PSM, /* Power Saving Mode - deep sleep */
 PS_EDRX /* Extended DRX - periodic wake */
} PowerState;

/* IoT device structure */
typedef struct {
 int device_id;
 char device_type[32];
 PowerState power_state;
 int messages_per_hour;
 float data_size_kb;
 bool connected;
} IoTDevice;

/* Network cell structure */
typedef struct {
 char technology[16];
 int max_capacity;
 int current_connections;
 int active_devices; /* Devices in Active/Idle state */
 int sleep_devices; /* Devices in PSM/eDRX (resource efficient) */
 IoTDevice* devices[200000]; /* Array of connected devices */
} NetworkCell;

/* Initialize a network cell */
NetworkCell* create_cell(const char* tech, int capacity) {
 NetworkCell* cell = (NetworkCell*)malloc(sizeof(NetworkCell));
 if (cell == NULL) {
 printf("Error: Memory allocation failed\n");
 return NULL;
 }

 strncpy(cell->technology, tech, 15);
 cell->technology[15] = '\0';
 cell->max_capacity = capacity;
 cell->current_connections = 0;
 cell->active_devices = 0;
 cell->sleep_devices = 0;

 printf("Created %s cell with max capacity: %d connections\n", 
 tech, capacity);

 return cell;
}

/* Register a new IoT device to the cell */
bool register_device(NetworkCell* cell, IoTDevice* device) {
 if (cell == NULL || device == NULL) {
 return false;
 }

 /* Check capacity - but sleeping devices use less resources */
 int resource_equivalent = cell->active_devices + (cell->sleep_devices / 10);

 if (resource_equivalent >= cell->max_capacity) {
 printf("ERROR: Cell capacity exceeded! Cannot register device %d\n", 
 device->device_id);
 return false;
 }

 cell->devices[cell->current_connections] = device;
 cell->current_connections++;

 if (device->power_state == PS_ACTIVE || device->power_state == PS_IDLE) {
 cell->active_devices++;
 } else {
 cell->sleep_devices++;
 }

 return true;
}

/* Update device power state */
void update_device_state(NetworkCell* cell, int device_id, PowerState new_state) {
 for (int i = 0; i < cell->current_connections; i++) {
 if (cell->devices[i]->device_id == device_id) {
 PowerState old_state = cell->devices[i]->power_state;

 /* Update cell counters */
 bool was_active = (old_state == PS_ACTIVE || old_state == PS_IDLE);
 bool is_active = (new_state == PS_ACTIVE || new_state == PS_IDLE);

 if (was_active && !is_active) {
 cell->active_devices--;
 cell->sleep_devices++;
 } else if (!was_active && is_active) {
 cell->active_devices++;
 cell->sleep_devices--;
 }

 cell->devices[i]->power_state = new_state;
 printf("Device %d state: %s -> %s\n", device_id,
 (old_state == PS_ACTIVE ? "ACTIVE" : 
 old_state == PS_IDLE ? "IDLE" :
 old_state == PS_PSM ? "PSM" : "eDRX"),
 (new_state == PS_ACTIVE ? "ACTIVE" : 
 new_state == PS_IDLE ? "IDLE" :
 new_state == PS_PSM ? "PSM" : "eDRX"));
 return;
 }
 }
}

/* Print cell status report */
void print_cell_status(NetworkCell* cell) {
 printf("\n========================================\n");
 printf("Network Cell Status Report\n");
 printf("========================================\n");
 printf("Technology: %s\n", cell->technology);
 printf("Max Capacity: %d connections\n", cell->max_capacity);
 printf("Total Connected: %d\n", cell->current_connections);
 printf("Active/Idle: %d (using full resources)\n", cell->active_devices);
 printf("PSM/eDRX Sleep: %d (resource efficient)\n", cell->sleep_devices);

 int resource_usage = cell->active_devices + (cell->sleep_devices / 10);
 float utilization = (float)resource_usage / cell->max_capacity * 100;

 printf("Resource Usage: %d (%.1f%%)\n", resource_usage, utilization);
 printf("========================================\n\n");
}

/* Simulate IoT deployment scenario */
void simulate_deployment(NetworkCell* cell, int num_devices, float sleep_ratio) {
 printf("\n--- Simulating %d IoT device deployment ---\n", num_devices);
 printf("Target sleep ratio: %.0f%% devices in PSM/eDRX\n\n", sleep_ratio * 100);

 int sleep_count = (int)(num_devices * sleep_ratio);
 int active_count = num_devices - sleep_count;

 /* Create and register devices */
 for (int i = 1; i <= num_devices; i++) {
 IoTDevice* device = (IoTDevice*)malloc(sizeof(IoTDevice));
 if (device == NULL) continue;

 device->device_id = i;

 /* Assign device type */
 if (i % 4 == 0) strcpy(device->device_type, "smart_meter");
 else if (i % 4 == 1) strcpy(device->device_type, "environment_sensor");
 else if (i % 4 == 2) strcpy(device->device_type, "tracker");
 else strcpy(device->device_type, "alarm");

 /* Assign power state based on device type */
 if (i <= sleep_count) {
 device->power_state = PS_PSM; /* Most devices in sleep */
 } else {
 device->power_state = PS_ACTIVE;
 }

 device->messages_per_hour = rand() % 12 + 1; /* 1-12 messages/hour */
 device->data_size_kb = (rand() % 512 + 64) / 1000.0; /* 64B - 512KB */
 device->connected = true;

 if (!register_device(cell, device)) {
 free(device);
 break; /* Stop if capacity reached */
 }

 if (i % 10000 == 0 && i > 0) {
 printf("Registered %d devices...\n", i);
 }
 }

 printf("\nDeployment complete!\n");
 print_cell_status(cell);
}

int main() {
 printf("==============================================\n");
 printf("IoT Network Scalability Simulation\n");
 printf("Network Operator Requirements: Scalability\n");
 printf("==============================================\n");

 /* Scenario 1: Traditional 4G cell (not optimized for IoT) */
 printf("\n>>> SCENARIO 1: Traditional 4G Cell <<<\n");
 NetworkCell* cell4g = create_cell("4G", MAX_CONNECTIONS_4G);
 simulate_deployment(cell4g, 5000, 0.90); /* 90% in sleep mode */

 /* Scenario 2: NB-IoT cell (optimized for massive IoT) */
 printf("\n>>> SCENARIO 2: NB-IoT Cell <<<\n");
 NetworkCell* cellNBIoT = create_cell("NB-IoT", MAX_CONNECTIONS_NBIOT);
 simulate_deployment(cellNBIoT, 100000, 0.95); /* 95% in sleep mode */

 printf("\n=== KEY INSIGHTS ===\n");
 printf("1. Traditional 4G cells: Limited to ~2,000 connections\n");
 printf("2. NB-IoT cells: Support ~100,000 connections per tower\n");
 printf("3. PSM/eDRX devices use 10x fewer network resources\n");
 printf("4. Network operators REQUIRE these optimizations for massive IoT\n");

 /* Note: In production, proper memory cleanup would be needed */

 return 0;
}
